#include <numeric>
#include <iostream>
#include <vector>
#include <queue>
#include <unordered_map>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    vector<vector<int>> verticalOrder(TreeNode* root) {
        if (!root) return {};
        unordered_map<int, vector<int>> column_table;
        int min_column = 0, max_column = 0;
        queue<pair<TreeNode*, int>> q;
        q.push({root, 0});
        while (!q.empty()) {
            auto node = q.front().first;
            auto column = q.front().second;
            q.pop();
            if (node) {
                column_table[column].push_back(node->val);
                min_column = min(min_column, column);
                max_column = max(max_column, column);
                q.push({node->left, column - 1});
                q.push({node->right, column + 1});
            }
        }
        vector<vector<int>> result;
        for (int i = min_column; i <= max_column; ++i) {
            result.push_back(column_table[i]);
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<TreeNode*> nodes(n);
    for (int i = 0; i < n; ++i) {
        int val, left, right;
        cin >> val >> left >> right;
        nodes[i] = new TreeNode(val);
        if (left != -1) nodes[i]->left = nodes[left];
        if (right != -1) nodes[i]->right = nodes[right];
    }
    TreeNode* root = nodes[0];
    Solution sol;
    vector<vector<int>> ans = sol.verticalOrder(root);
    for (const auto& row : ans) {
        for (int val : row) {
            cout << val << " ";
        }
        cout << "\n";
    }
    return 0;
}
